-- {"operators": "INNER_JOIN,AGGREGATE,FILTER", "complexity": "high", "is_incremental": true, "has_nulls": false, "has_cast": false, "has_case": false, "tables": "CUSTOMER,OORDER,ORDER_LINE", "ducklake": true}
SELECT c.C_W_ID, c.C_D_ID, c.C_ID, SUM(ol.OL_AMOUNT) AS spent FROM dl.CUSTOMER c JOIN dl.OORDER o ON c.C_W_ID = o.O_W_ID AND c.C_D_ID = o.O_D_ID AND c.C_ID = o.O_C_ID JOIN dl.ORDER_LINE ol ON o.O_W_ID = ol.OL_W_ID AND o.O_D_ID = ol.OL_D_ID AND o.O_ID = ol.OL_O_ID WHERE c.C_CREDIT = 'GC' GROUP BY c.C_W_ID, c.C_D_ID, c.C_ID;
